[
  {
    "op": "MODIFY",
    "section": "confirmation_communication",
    "target_id": "conf-006",
    "content": "IF a proposed action requires user confirmation (a specific exchange/modify/cancel/return) → THEN by default do NOT execute the tool call until the user gives an explicit confirmation. Before requesting that explicit confirmation the assistant MUST: (a) present the exact proposed action including order id(s), current item_ids, proposed new_item_ids (or cancellation), and the payment method to be used; (b) compute all refund(s), charge(s), and combined totals using calculate(...) and present those exact amounts rounded to two decimal places; (c) when a return/refund is involved, present the estimated refund processing time. An explicit confirmation MUST unambiguously accept the exact proposed action including the exact computed totals and payment method. Acceptable confirmations include clear affirmatives that reference the stated order id(s), item_ids, new_item_ids (or cancellation), the exact refund or charge amount(s), and the payment method. Do NOT treat generic acknowledgements or conversational replies (for example: 'Okay', 'Thanks', 'What's next?', 'Sure') as explicit confirmation to proceed. Only clear commands that directly instruct the assistant to proceed (for example: 'Please return this tablet', 'Go ahead and cancel that order', 'Yes, process the exchange now') may be treated as immediate confirmation under the EXCEPTION rules. If the assistant is unsure whether the user's reply counts as explicit confirmation, request a clarified, unambiguous confirmation before executing any tool calls.",
    "rationale": "Trajectories showed a return action executed after a conversational reply rather than an explicit unambiguous confirmation (conversation 1). Clarifies what counts as confirmation so tool calls aren't made on ambiguous user responses.",
    "source_task_ids": [
      2
    ]
  },
  {
    "op": "ADD",
    "section": "information_gathering",
    "target_id": null,
    "content": "IF a user is unsure which payment method was used for a referenced order or asks where a refund will be returned → THEN locate the relevant order (call get_order_details(order_id) after identifying the user if needed) and inspect the order's payment_history to identify the original payment method. Present the original payment method id and last-four (or type) to the user and use it as the default for any refunds/charges unless the user explicitly specifies an alternate allowed method. Do NOT ask the user to name the payment method before checking order/payment history when order data is available.",
    "rationale": "Users sometimes don't remember which payment method they used; assistant should look this up in order details rather than guessing or prompting the user unnecessarily (observed in conversations where user was unsure and assistant proceeded without first retrieving payment history).",
    "source_task_ids": [
      2,
      25
    ]
  },
  {
    "op": "ADD",
    "section": "precondition_rules",
    "target_id": null,
    "content": "IF a user requests a refund/return routing that is disallowed by the system (for example: refund to a different payment method than the original) AND the user insists on making an exception → THEN offer to escalate the request to human agents by calling transfer_to_human_agents(...) with a concise summary (order_id, original payment method, requested exception, user's justification, and any prior steps taken). Ask the user for permission to transfer before escalating, inform the user what to expect from escalation, and proceed with transfer only after the user agrees.",
    "rationale": "When users insist on refunds to non-original payment methods the assistant should provide a clear escalation path to humans rather than only refusing; observed in conversation where user insisted on Amex instead of PayPal and was transferred (conversation 4).",
    "source_task_ids": [
      25
    ]
  }
]

